            try:
                content_str = content.decode('utf-16-le')
            except Exception:
                try:
                    content_str = content.decode('utf-8', errors='ignore')
                except Exception:
                    content_str = ""

            for pat in patterns:
                if pat in content_str:
                    print(f"Found '{pat}' in {name}")
                    idx = content_str.find(pat)
